      "title": "Basic Electron Theory",
      "basicQuestions": [
        {
          "questionText": "What is the name of the central part of an atom that contains protons and neutrons?",
          "answerGuidance": [
            "Nucleus",
            "The center of the atom",
            "The engine room"
          ]
        },
        {
          "questionText": "Which specific particle in an atom carries a negative charge and orbits the center?",
          "answerGuidance": [
            "Electron",
            "Negative particles",
            "The moving parts"
          ]
        },
        {
          "questionText": "What is the technical term for the outermost shell of an atom where electrical movement occurs?",
          "answerGuidance": [
            "Valence shell",
            "Outer shell",
            "Outermost orbit"
          ]
        }
      ],
      "deeperQuestionText": "Why is the movement of electrons in the valence shell the primary focus for an electrician rather than the particles in the nucleus?",
      "deeperAnswerGuidance": [
        "Electricity is the flow of electrons between atoms",
        "The nucleus remains fixed in place",
        "Only valence electrons are able to move to neighboring atoms",
        "Current cannot flow without moving negative particles"
      ],
      "hint": "Focus on which part of the atom is fixed and which part is the 'moving part' that creates a current."
    },
    {
      "title": "Conductors vs Insulators",
      "basicQuestions": [
        {
          "questionText": "What is the specific term for electrons in a conductor that are loosely held and able to jump between atoms?",
          "answerGuidance": [
            "Free electrons",
            "Loosely held electrons",
            "Moving valence electrons"
          ]
        },
        {
          "questionText": "Which common insulating material is used to wrap conductors to prevent short circuits?",
          "answerGuidance": [
            "PVC",
            "Rubber",
            "Glass"
          ]
        },
        {
          "questionText": "What is the state of electrons in an insulator that prevents them from moving between atoms?",
          "answerGuidance": [
            "Tightly bound",
            "Locked",
            "Strongly held to the nucleus"
          ]
        }
      ],
      "deeperQuestionText": "If an insulator like PVC actually contains many electrons, why does it still stop the flow of electricity?",
      "deeperAnswerGuidance": [
        "The electrons are not free to move",
        "They are bound tightly to their own atoms",
        "They cannot jump to neighboring atoms",
        "The material acts like a brick wall to electron traffic"
      ],
      "hint": "Consider the difference between having electrons and having 'free' electrons that can move."
    }
  ]
}

{
  "integrative": {
    "title": "Integrative Close: The Anatomy of a Cable",
    "objective": "Connect the concept of electron movement to the practical necessity of using specific materials in electrical cables and enclosures.",
    "retrievalTextLines": [
      "You now know that electricity isn't magic; it is the physical movement of negative particles called electrons.",
      "The difference between a material that carries current and one that stops it comes down to the 'grip' the nucleus has on the electrons in the valence shell."
    ],
    "questionText": "Consider a standard electrical cable consisting of a copper internal core and a PVC outer sheath. Using the 'free electron' theory, explain how the atomic structure of these two specific materials allows the cable to both conduct electricity and remain safe to touch.",
    "answerGuidance": [
      "Copper is a conductor because it has loosely held electrons in its valence shell.",
      "These 'free electrons' in the copper can easily move from atom to atom to create an electrical current.",
      "PVC is an insulator because its electrons are tightly bound to the nucleus and cannot move between atoms.",
      "The lack of free electrons in the PVC prevents the flow of electricity to the outside of the cable, making it safe to touch."
    ],
    "hint": "Think about the 'valence shell' of each material and whether the electrons there are 'free' to move or 'locked' in place."
  }
}

